test_that("inspect.stance_result: error handling (out of bounds and missing sections)", {
  # 1. Invalid 'within' section
  expect_error(
    inspect(mock_res, what = "analysis", within = "wrong"),
    "not found in analysis",
    fixed = TRUE
  )
  expect_error(
    inspect(mock_res, what = "debates", within = "wrong"),
    "not found in debates",
    fixed = TRUE
  )

  # 2. Index out of bounds
  expect_error(
    inspect(mock_res, what = "analysis", within = "linguistic", index = 99),
    "out of bounds"
  )
  expect_error(
    inspect(mock_res, what = "explanation", index = 99),
    "out of bounds"
  )
  expect_error(
    inspect(mock_res, what = "debates", within = "positive", index = 99),
    "out of bounds"
  )

  # 3. Invalid index type
  expect_error(inspect(mock_res, index = 0), "must be a whole number")
  
  # 4. Empty
  mock_res_empty <- mock_res
  mock_res_empty$analysis$linguistic[1] <- NA_character_
  expect_output(
    inspect(mock_res_empty, "analysis", "linguistic", 1),
    "(empty)",
    fixed = TRUE
  )
  mock_res_empty <- mock_res
  mock_res_empty$debates$negative[2] <- NA_character_
  expect_output(
    inspect(mock_res_empty, "debates", "negative", 2),
    "(empty)",
    fixed = TRUE
  )
  mock_res_empty <- mock_res
  mock_res_empty$summary$explanation[1] <- NA_character_
  expect_output(
    inspect(mock_res_empty, "explanation", index = 1),
    "(empty)",
    fixed = TRUE
  )
})
